#include <iostream>

using namespace std;

int main()
{
    int n;
    cout << "How many scores? ";
    cin >> n;

    int *scores = new int[n]; // size decided at RUNTIME

    for (int i = 0; i < n; i++)
    {
        scores[i] = (i + 1) * 10;
    }

    for (int i = 0; i < n; i++)
    {
        cout << scores[i] << " ";
    }

    delete[] scores;

    return 0;
}

